from typing import List

class Solution:
    def find132pattern(self, nums: List[int]) -> bool:
        if len(nums) < 3:
            return False
        third = float('-inf')
        stack = []
        for i in range(len(nums) - 1, -1, -1):
            if nums[i] < third:
                return True
            while stack and nums[i] > stack[-1]:
                third = max(third, stack.pop())
            stack.append(nums[i])
        return False


def brute(nums):
    n = len(nums)
    for i in range(n):
        for j in range(i + 1, n):
            for k in range(j + 1, n):
                if nums[i] < nums[k] < nums[j]:
                    return True
    return False


s = Solution()
# samples
print(s.find132pattern([1, 2, 3, 4]))   # False
print(s.find132pattern([3, 1, 4, 2]))   # True
# edges
print(s.find132pattern([1]))            # False
print(s.find132pattern([2, 1]))         # False
print(s.find132pattern([-1, 3, 2, 0]))  # True
print(s.find132pattern([3, 3, 3]))      # False (strict)
print(s.find132pattern([1, 1, 1, 1]))   # False

# randomized vs brute
import random
ok = True
for _ in range(20000):
    arr = [random.randint(-6, 6) for _ in range(random.randint(0, 8))]
    if s.find132pattern(arr) != brute(arr):
        ok = False
        print("MISMATCH", arr)
        break
print("random match:", ok)
